import { useState, useEffect, useRef } from 'react';
import { MapPin, Clock, ArrowRight, ChevronDown, Send, Briefcase, Users, Zap, Globe, Shield, Code, Palette, BarChart2, Cpu, Terminal, Smartphone } from 'lucide-react';

/* ═══════════════════════════════════════════ DATA ══ */
const PERKS = [
  { icon:'🚀', title:'Real Projects Day One', body:'No busywork. You ship to real users from your first sprint.' },
  { icon:'🎓', title:'Senior Mentorship', body:'Weekly 1:1s with senior engineers — structured, not accidental.' },
  { icon:'🌍', title:'Remote & Hybrid', body:'Work from anywhere. Results matter, not desk hours.' },
  { icon:'📈', title:'Clear Growth Path', body:'Defined tracks from intern → junior → senior. No guessing.' },
  { icon:'🤝', title:'Collaborative Culture', body:'We build together. No silos, no politics, no egos.' },
  { icon:'⚡', title:'Full Product Lifecycle', body:'Strategy, design, build, launch — you see all of it.' },
];

const STATS = [
  { val:50, suffix:'+', label:'Projects shipped' },
  { val:8,  suffix:'',    label:'Departments hiring' },
  { val:3,  suffix:' mo', label:'Internship duration' },
  { val:100, suffix:'%', label:'Remote-friendly' },
];

const DEPT_ICONS = { 'Full Stack':Code, 'Game Dev':Zap, 'UI/UX':Palette, 'Data':BarChart2, 'Security':Shield, 'Mobile':Smartphone, 'IoT':Cpu, 'DevOps':Terminal };

const INTERNS = [
  { role:'Full Stack Dev Intern', dept:'Full Stack', dur:'3 Months', mode:'Remote / Hybrid', col:'#0057ff', rgb:'0,87,255',
    resp:['Build and test web features using React and Node.js','Write clean, documented code under senior guidance','Participate in standups, sprints, and code reviews','Contribute to UI, API integrations, and database queries'],
    req:['Basic knowledge of HTML, CSS, JavaScript / React','Familiarity with Node.js or any backend framework is a plus','Strong willingness to learn and contribute'] },
  { role:'Game Dev Intern (Unity/Unreal)', dept:'Game Dev', dur:'3 Months', mode:'Remote / Hybrid', col:'#7c3aed', rgb:'124,58,237',
    resp:['Work on active game projects in the studio','Implement gameplay features, mechanics, and UI elements','Contribute to QA testing and performance optimisation','Assist with asset integration and scene management'],
    req:['Basic knowledge of Unity (C#) or Unreal Engine','Interest in game design or interactive media','Portfolio or game jam experience is a strong plus'] },
  { role:'UI/UX Design Intern', dept:'UI/UX', dur:'3 Months', mode:'Remote / Hybrid', col:'#db2777', rgb:'219,39,119',
    resp:['Create wireframes, prototypes, and mockups in Figma','Contribute to design system components','Collaborate with developers on implementation','Conduct basic user research and compile insights'],
    req:['Proficiency in Figma or equivalent tools','Eye for visual design, typography, and layout','Portfolio with 1–2 UI design projects'] },
  { role:'Data Analyst Intern', dept:'Data', dur:'3 Months', mode:'Remote / Hybrid', col:'#0891b2', rgb:'8,145,178',
    resp:['Collect, clean and organise datasets','Build dashboards using Power BI or Google Data Studio','Identify trends and patterns from business data','Document data sources and maintain reporting templates'],
    req:['Basic knowledge of Python or SQL','Familiarity with Excel or any BI tool','Analytical mindset with attention to detail'] },
  { role:'Cyber Security Intern', dept:'Security', dur:'3 Months', mode:'Remote / Hybrid', col:'#059669', rgb:'5,150,105',
    resp:['Assist in vulnerability assessments and security audits','Monitor systems for threats and document findings','Support implementation of security policies','Research emerging threats and contribute to reports'],
    req:['Basic understanding of networking and attack vectors','Familiarity with tools like Wireshark or Nmap is a plus','Strong interest in ethical hacking'] },
  { role:'App Developer Intern', dept:'Mobile', dur:'3 Months', mode:'Remote / Hybrid', col:'#f59e0b', rgb:'245,158,11',
    resp:['Build and test mobile app features for iOS or Android','Write clean, maintainable code under senior guidance','Participate in design reviews and UI implementation','Debug issues and optimise app performance'],
    req:['Basic knowledge of Flutter, React Native, or native iOS/Android','Familiarity with REST APIs and JSON','Eagerness to learn and ship real mobile features'] },
  { role:'IoT Engineer Intern', dept:'IoT', dur:'3 Months', mode:'Remote / Hybrid', col:'#8b5cf6', rgb:'139,92,246',
    resp:['Prototype and test IoT hardware/software integrations','Write embedded code to communicate with sensors','Contribute to cloud data pipelines from IoT devices','Document hardware setups and firmware configurations'],
    req:['Basic knowledge of Arduino, Raspberry Pi, or similar','Familiarity with C/C++, Python, or MicroPython','Interest in embedded systems and hardware-software integration'] },
  { role:'DevOps Engineer Intern', dept:'DevOps', dur:'3 Months', mode:'Remote / Hybrid', col:'#ef4444', rgb:'239,68,68',
    resp:['Set up and maintain CI/CD pipelines','Support cloud infrastructure on AWS or Azure','Monitor system performance and incident response','Automate deployment and configuration tasks'],
    req:['Basic knowledge of Linux, shell scripting, and Git','Familiarity with Docker or any CI/CD tool','Interest in cloud platforms and system reliability'] },
];

const FULL_TIME = [
  { role:'Senior Full Stack Developer', dept:'Full Stack', exp:'3+ years', mode:'Remote / Hybrid', col:'#0057ff', rgb:'0,87,255', req:'React, Node.js, REST APIs, PostgreSQL / MongoDB, Docker, AWS/Azure', nice:'GraphQL, microservices, CI/CD pipeline ownership' },
  { role:'Game Developer (Unity)', dept:'Game Dev', exp:'2+ years', mode:'Remote / Hybrid', col:'#7c3aed', rgb:'124,58,237', req:'C#, Unity Engine, multiplayer/Photon experience, mobile optimisation', nice:'Unreal Engine, shader programming, game analytics' },
  { role:'UI/UX Designer', dept:'UI/UX', exp:'2+ years', mode:'Remote / Hybrid', col:'#db2777', rgb:'219,39,119', req:'Figma expert, design systems, responsive & accessible design — portfolio required', nice:'Motion design, Framer, basic HTML/CSS understanding' },
  { role:'Data Analyst', dept:'Data', exp:'2+ years', mode:'Remote / Hybrid', col:'#0891b2', rgb:'8,145,178', req:'Python or SQL, Power BI or Tableau, strong analytical skills', nice:'BigQuery, dbt, or data pipeline tooling' },
  { role:'Cyber Security Engineer', dept:'Security', exp:'2+ years', mode:'Remote / Hybrid', col:'#059669', rgb:'5,150,105', req:'VAPT experience, OWASP Top 10, networking and firewall management', nice:'CEH/OSCP certification, SIEM tools, cloud security' },
  { role:'App Developer', dept:'Mobile', exp:'2+ years', mode:'Remote / Hybrid', col:'#f59e0b', rgb:'245,158,11', req:'Flutter or React Native, REST API integration, mobile performance optimisation', nice:'Native iOS (Swift) or Android (Kotlin), Firebase, app store deployment' },
  { role:'IoT Engineer', dept:'IoT', exp:'2+ years', mode:'Remote / Hybrid', col:'#8b5cf6', rgb:'139,92,246', req:'C/C++ or Python for embedded systems, MQTT/HTTP protocols, AWS IoT or Azure IoT Hub', nice:'PCB design basics, RTOS experience, industrial IoT ecosystems' },
  { role:'DevOps Engineer', dept:'DevOps', exp:'2+ years', mode:'Remote / Hybrid', col:'#ef4444', rgb:'239,68,68', req:'Docker, Kubernetes, Terraform or Ansible, strong Linux and scripting skills', nice:'GitOps workflows, Prometheus/Grafana monitoring, multi-cloud experience' },
];

/* ══════════════════════════════════════════ HOOKS ══ */
function useScrollProg(ref) {
  const [p, setP] = useState(0);
  useEffect(() => {
    const fn = () => {
      if (!ref.current) return;
      const r = ref.current.getBoundingClientRect();
      setP(Math.min(1, Math.max(0, -r.top / (r.height - window.innerHeight))));
    };
    window.addEventListener('scroll', fn, { passive: true }); fn();
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return p;
}

function useInView(threshold = 0.1) {
  const ref = useRef(null); const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVis(true); io.disconnect(); } }, { threshold });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [threshold]);
  return [ref, vis];
}

function useCounter(target, running) {
  const [val, setVal] = useState(0);
  useEffect(() => {
    if (!running) return;
    let start = null;
    const dur = 1600;
    const step = (ts) => {
      if (!start) start = ts;
      const p = Math.min((ts - start) / dur, 1);
      const ease = 1 - Math.pow(1 - p, 3);
      setVal(Math.round(ease * target));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [running, target]);
  return val;
}

/* ══════════════════════════════════════ COMPONENTS ══ */
function Grain() {
  return (
    <div style={{ position:'fixed', inset:0, zIndex:9999, pointerEvents:'none', opacity:.022 }}>
      <svg width="100%" height="100%"><filter id="crg"><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch"/><feColorMatrix type="saturate" values="0"/></filter><rect width="100%" height="100%" filter="url(#crg)"/></svg>
    </div>
  );
}

function ProgressBar() {
  const [p, setP] = useState(0);
  useEffect(() => {
    const fn = () => { const d = document.documentElement; setP(d.scrollTop / (d.scrollHeight - d.clientHeight)); };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return (
    <div style={{ position:'fixed', top:0, left:0, right:0, height:3, zIndex:9999 }}>
      <div style={{ height:'100%', background:'linear-gradient(90deg,#0057ff,#7c3aed,#db2777)', transformOrigin:'left', transform:`scaleX(${p})`, transition:'none', willChange:'transform' }} />
    </div>
  );
}

/* ── HERO ── */
const HERO_ROLES = [
  { label:'Full Stack Dev',      col:'#0057ff', rgb:'0,87,255'   },
  { label:'Game Developer',      col:'#7c3aed', rgb:'124,58,237' },
  { label:'UI/UX Designer',      col:'#db2777', rgb:'219,39,119' },
  { label:'DevOps Engineer',     col:'#ef4444', rgb:'239,68,68'  },
  { label:'Data Analyst',        col:'#0891b2', rgb:'8,145,178'  },
  { label:'Security Engineer',   col:'#059669', rgb:'5,150,105'  },
  { label:'App Developer',       col:'#f59e0b', rgb:'245,158,11' },
  { label:'IoT Engineer',        col:'#8b5cf6', rgb:'139,92,246' },
];

function Hero() {
  const wRef = useRef(null);
  const prog = useScrollProg(wRef);
  // Split scroll into 2 phases over 130vh:
  // 0→0.45  = hero content visible, parallax image drifts
  // 0.45→1  = role cards reveal from right, hero text stays readable
  const imgTy    = prog * 80;
  const textFade = Math.max(0, 1 - prog * 3.5);   // fades fast at start of scroll
  const cardsP   = Math.max(0, (prog - 0.3) / 0.7); // cards enter after 30% scroll
  const cardsE   = 1 - Math.pow(1 - Math.min(1, cardsP), 3);

  return (
    <div ref={wRef} style={{ height:'130vh', position:'relative' }}>
      <section style={{ position:'sticky', top:0, height:'100vh', overflow:'hidden', background:'#020810' }}>

        {/* BG parallax */}
        <div style={{ position:'absolute', inset:'-10% 0', transform:`translateY(${imgTy}px) translateZ(0)`, willChange:'transform', transition:'none' }}>
          <img src="https://images.unsplash.com/photo-1521737711867-e3b97375f902?w=1800&q=75" alt=""
            style={{ width:'100%', height:'100%', objectFit:'cover', filter:'saturate(.3) brightness(.18)' }} />
        </div>

        {/* Overlays */}
        <div style={{ position:'absolute', inset:0, background:'linear-gradient(135deg,rgba(0,87,255,.18) 0%,rgba(124,58,237,.12) 50%,transparent 100%)', pointerEvents:'none' }} />
        <div style={{ position:'absolute', inset:0, background:'linear-gradient(to bottom,rgba(2,8,16,.25) 0%,rgba(2,8,16,.45) 60%,#020810 100%)', pointerEvents:'none' }} />
        <div style={{ position:'absolute', inset:0, backgroundImage:'linear-gradient(rgba(255,255,255,.03) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.03) 1px,transparent 1px)', backgroundSize:'72px 72px', pointerEvents:'none' }} />
        <div style={{ position:'absolute', top:'-20%', right:'-10%', width:'60vw', height:'60vw', borderRadius:'50%', background:'radial-gradient(circle,rgba(0,87,255,.22) 0%,transparent 65%)', pointerEvents:'none', animation:'orbA 9s ease-in-out infinite' }} />
        <div style={{ position:'absolute', bottom:'-15%', left:'5%', width:'45vw', height:'45vw', borderRadius:'50%', background:'radial-gradient(circle,rgba(124,58,237,.18) 0%,transparent 65%)', pointerEvents:'none', animation:'orbB 12s ease-in-out infinite' }} />

        {/* LEFT — headline (always present, just fades) */}
        <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', justifyContent:'center', padding:'0 clamp(24px,7vw,80px)', maxWidth:'55%', opacity: Math.max(0.12, textFade), transition:'none', willChange:'opacity' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:24, animation:'cUp .6s .05s both' }}>
            <Briefcase size={12} color="#0057ff" />
            <span style={{ fontSize:'.6rem', fontWeight:700, letterSpacing:'.24em', textTransform:'uppercase', color:'rgba(255,255,255,.42)' }}>Join the Team</span>
            <div style={{ width:28, height:1, background:'rgba(255,255,255,.15)' }} />
            <span style={{ fontSize:'.6rem', fontWeight:700, color:'rgba(0,87,255,.8)' }}>16 Open Roles</span>
          </div>

          <div style={{ overflow:'hidden', marginBottom:3 }}>
            <h1 style={{ fontFamily:'var(--serif)', fontSize:'clamp(3rem,8.5vw,8rem)', fontWeight:900, color:'#fff', letterSpacing:'-.055em', lineHeight:.88, margin:0, animation:'cUp .8s .08s both' }}>Build</h1>
          </div>
          <div style={{ overflow:'hidden', marginBottom:3 }}>
            <h1 style={{ fontFamily:'var(--serif)', fontSize:'clamp(3rem,8.5vw,8rem)', fontWeight:900, letterSpacing:'-.055em', lineHeight:.88, margin:0, animation:'cUp .8s .16s both', background:'linear-gradient(90deg,#4d9fff,#a78bfa)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text' }}>Meaningful</h1>
          </div>
          <div style={{ overflow:'hidden', marginBottom:28 }}>
