      <div style={{ display:'flex', gap:28, animation:'tickL 22s linear infinite', whiteSpace:'nowrap', willChange:'transform' }}>
        {[...roles,...roles,...roles].map((w,i) => <span key={i} style={{ fontSize:'.7rem', fontWeight:700, letterSpacing:'.14em', textTransform:'uppercase', color:'rgba(255,255,255,.82)', flexShrink:0 }}>{w}</span>)}
      </div>
    </div>
  );
}

